const intent = $json.intent || '';
const params = $json.intentParams || {};
const accessToken = $json.accessToken || '';
if (!accessToken) { return [{ json: { ...$json, responseText: '⚠️ Google Auth failed: no access token.', success: false } }]; }
let endpoint, body, method = 'GET';
const spreadsheetId = params.spreadsheet_id || params.id;
if (intent === 'sheets_read') {
  const range = params.range || 'Sheet1!A1:C10';
  endpoint = `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/${encodeURIComponent(range)}`;
} else if (intent === 'sheets_write') {
  const range = params.range || 'Sheet1!A1';
  endpoint = `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/${encodeURIComponent(range)}`;
  method = 'PUT';
  body = { values: params.values || [[]] };
} else if (intent === 'sheets_create') {
  endpoint = 'https://sheets.googleapis.com/v4/spreadsheets';
  method = 'POST';
  body = { properties: { title: params.title || 'New Spreadsheet' } };
} else { return [{ json: { ...$json, responseText: '❓ Unknown Sheets intent: ' + intent, success: false } }]; }
if (!spreadsheetId && intent !== 'sheets_create') { return [{ json: { ...$json, responseText: '❗ Spreadsheet ID required.', success: false } }]; }
return [{ json: { ...$json, apiEndpoint: endpoint, apiBody: body, apiMethod: method, range: params.range, bearerToken: accessToken, _ctx: { intent, params, accessToken, source: $json.source, userId: $json.userId, sessionId: $json.sessionId, inputText: $json.inputText } } }];

const ctx = $json._ctx || $('Build Request').first().json._ctx || {};
const values = $json.values;
if ($json.spreadsheetId && $json.properties) {
  const url = `https://docs.google.com/spreadsheets/d/${$json.spreadsheetId}/edit`;
  return [{ json: { ...ctx, responseText: `📊 Spreadsheet created!

<b>${$json.properties.title}</b>

🔗 ${url}`, success: true, intent: ctx.intent } }];
}
if (values) {
  let text = `📊 Data (${$json.range || ctx.params?.range || 'unknown range'}):

`;
  values.forEach(row => { text += row.join(' | ') + '\n'; });
  return [{ json: { ...ctx, responseText: text, success: true, intent: ctx.intent } }];
}
if ($json.updatedCells !== undefined) { return [{ json: { ...ctx, responseText: `✅ ${$json.updatedCells} cell(s) updated.`, success: true, intent: ctx.intent } }]; }
return [{ json: { ...ctx, responseText: `📊 Sheets operation completed.`, success: true, intent: ctx.intent } }];

const ctx = $json._ctx || $('Build Request').first().json._ctx || {};
const jarvisLog = (level, message, meta = {}) => {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  const configLevel = ($env.LOG_LEVEL || 'info').toLowerCase();
  if (levels[level] >= (levels[configLevel] ?? 1)) { console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](JSON.stringify({ timestamp: new Date().toISOString(), level, traceId: ctx.sessionId || 'unknown', workflow: 'sheets-agent', message, meta })); }
};
const statusCode = $json.statusCode || $json.error?.statusCode || 0;
const statusMessage = $json.statusMessage || $json.error?.message || 'Unknown error';
if (statusCode === 401) {
  jarvisLog('warn', 'Token expired, attempting refresh', { intent: ctx.intent });
  try {
    const authRes = await $helpers.httpRequest({ method: 'POST', url: 'https://oauth2.googleapis.com/token', headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, body: 'client_id=' + encodeURIComponent($env.GOOGLE_CLIENT_ID) + '&client_secret=' + encodeURIComponent($env.GOOGLE_CLIENT_SECRET) + '&refresh_token=' + encodeURIComponent($env.GOOGLE_REFRESH_TOKEN) + '&grant_type=refresh_token', timeout: 15000 });
    const retryRes = await $helpers.httpRequest({ method: $('Build Request').first().json.apiMethod || 'GET', url: $('Build Request').first().json.apiEndpoint, headers: { 'Authorization': 'Bearer ' + authRes.access_token }, body: $('Build Request').first().json.apiBody, timeout: 15000 });
    return [{ json: { ...retryRes, _ctx: ctx } }];
  } catch (retryErr) {
    jarvisLog('error', 'Auth retry failed', { intent: ctx.intent, error: retryErr.message });
    return [{ json: { ...ctx, responseText: '⚠️ Authentication failed after refresh. Please re-authenticate Google OAuth.', success: false, intent: ctx.intent } }];
  }
}
jarvisLog('error', 'API request failed', { intent: ctx.intent, statusCode, statusMessage });
return [{ json: { ...ctx, responseText: '⚠️ Could not complete your request. API returned error ' + statusCode + ': ' + statusMessage + '. Please try again.', success: false, intent: ctx.intent, error: { statusCode, provider: 'sheets', intent: ctx.intent } } }];
